 * object on stdout with device info, device id, and battery info.
 *
 * Because @capacitor/device's web implementation reads from browser globals
 * (navigator, window, localStorage) we install a minimal shim before
 * importing the plugin so it can execute outside a real browser.
 */

// ── Minimal browser-global shims ─────────────────────────────────────────────

const _localStorage = (() => {
  const store = {};
  return {
    getItem: (k) => (k in store ? store[k] : null),
    setItem: (k, v) => { store[k] = String(v); },
  };
})();

if (typeof globalThis.window === 'undefined') {
  globalThis.window = globalThis;
}

if (typeof globalThis.navigator === 'undefined') {
  globalThis.navigator = {};
}

// Provide a realistic Node.js user-agent so the UA parser in DeviceWeb
// can extract a meaningful osVersion / operatingSystem string.
if (!globalThis.navigator.userAgent) {
  globalThis.navigator.userAgent =
    'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 ' +
    '(KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36';
}

if (!globalThis.navigator.vendor) {
  globalThis.navigator.vendor = 'Google Inc.';
}

// getBattery shim – returns a resolved battery status object
if (!globalThis.navigator.getBattery) {
  globalThis.navigator.getBattery = () =>
    Promise.resolve({ level: 1, charging: true });
}

// localStorage shim (used by DeviceWeb.getUid)
if (!globalThis.window.localStorage) {
  globalThis.window.localStorage = _localStorage;
}

// ── Import plugin (after shims are in place) ─────────────────────────────────

import { Device } from '@capacitor/device';

// ── Gather information ────────────────────────────────────────────────────────

const [info, id, battery] = await Promise.all([
  Device.getInfo(),
  Device.getId(),
  Device.getBatteryInfo(),
]);

// ── Emit result ───────────────────────────────────────────────────────────────

const result = {
  info: {
    platform: info.platform,
    operatingSystem: info.operatingSystem,
    osVersion: info.osVersion,
    manufacturer: info.manufacturer,
    model: info.model,
    isVirtual: info.isVirtual,
    webViewVersion: info.webViewVersion,
  },
  id: {
    identifier: id.identifier,
  },
  battery: {
    batteryLevel: battery.batteryLevel,
    isCharging: battery.isCharging,
  },
};

process.stdout.write(JSON.stringify(result) + '\n');

